INSERT INTO public.assistant_conversations VALUES (1, 3, 2, 'How to edit a message?', '[{"role": "user", "content": "How to edit a message?"}, {"role": "assistant", "content": "Okay, here’s how to edit a message in TheChatNest:\n\n1.  **Locate the Message:** Find the message you want to edit within the chat.\n2.  **Right-Click:** Right-click on the message.\n3.  **Select \"Edit\":** From the context menu that appears, click on the \"Edit\" option.\n\n*Note:* There might be a time limit on how long you have to edit a message. If the \"Edit\" option is greyed out, it means the time limit has expired."}]', 1, '2026-03-18 18:57:01.206327+05:30', '2026-03-18 18:57:01.206327+05:30');
INSERT INTO public.assistant_conversations VALUES (3, 3, 2, '**Hello**', '[{"role": "user", "content": "**Hello**"}, {"role": "assistant", "content": "Hello there! How can I help you with TheChatNest today?"}, {"role": "user", "content": "file kaise share karte hain chat mein?"}, {"role": "assistant", "content": "Okay, let’s go through how to share files in TheChatNest. Here’s how you can do it:\n\n1.  **Open the Chat:** Navigate to the chat window where you want to share the file.\n2.  **Attach the File:** Click the paperclip icon (📎) located in the message input field – it’s usually in the bottom right corner.\n3.  **Select the File:** A file explorer window will open. Browse your computer to find the file you want to share. Select the file and click “Open”.\n4.  **File Preview (Optional):** TheChatNest will often show you a preview of the file (image, PDF, document, etc.) directly in the chat window.\n5.  **Send the File:** Once you’ve selected the file, click the “Send” button.\n\n**Important Notes:**\n\n*   The maximum file size you can share is 2GB per file.\n*   Supported file types include images, videos, audio, PDFs, Word documents, Excel spreadsheets, and more.  Executable files (.exe, .bat, .dll, .msi) are not supported for security reasons."}, {"role": "user", "content": "Office ka WiFi password kya hai?"}, {"role": "assistant", "content": "I understand you’re looking for the Office WiFi password. However, as a TheChatNest AI Assistant, I don’t have access to private information like WiFi passwords. That kind of data is confidential and only accessible to authorized personnel within your organization.\n\nTo find the Office WiFi password, you’ll need to:\n\n1.  **Ask your IT administrator:** They will be able to provide you with the correct password.\n2.  **Check the IT helpdesk:** Your organization’s IT helpdesk is another resource for getting the password."}, {"role": "user", "content": "Users Kaise Add kru"}, {"role": "assistant", "content": "Okay, let’s go through how to add users to your TheChatNest workspace. Since you’re a regular user, I’ll guide you on how to do this through the chat features.\n\n1.  **Navigate to Groups:** First, you need to go to the group where you want to add users. Click on the group icon in the chat list header. This will open the group info sidebar.\n\n2.  **Access Group Members:** In the group info sidebar, look for the \"Members\" section. It’s usually located towards the bottom.\n\n3.  **Add New Member:** Click the “Add Member” button. This might be a plus (+) icon or a button that says “Add Member”.\n\n4.  **Search for Users:** A search bar will appear. Type the name or email address of the user you want to add. TheChatNest will display a list of matching users.\n\n5.  **Select User:** Click on the user’s name from the search results.\n\n6.  **Confirm Addition:** The user will be added to the group. You might see a confirmation message.\n\n**Important Notes:**\n\n*   Make sure you have the necessary permissions to add users to the group.\n*   You can only add users who are already part of your TheChatNest workspace."}]', 4, '2026-03-19 15:06:14.950898+05:30', '2026-03-19 15:11:37.10424+05:30');
INSERT INTO public.assistant_conversations VALUES (4, 3, 2, 'How to edit a message?', '[{"role": "user", "content": "How to edit a message?"}, {"role": "assistant", "content": "Okay, here’s how to edit a message in TheChatNest:\n\n1.  **Locate the Message:** Find the message you want to edit within the chat.\n2.  **Right-Click:** Right-click on the message.\n3.  **Select \"Edit\":** From the context menu that appears, click on the \"Edit\" option.\n4.  **Make Your Changes:** The message text box will open, allowing you to modify the text.\n5.  **Save Changes:** Once you’ve made your edits, click the \"Save\" button (it might appear automatically after a short delay).\n\n**Important Note:** There might be a time limit on how long you have to edit a message. If the \"Save\" button disappears, the editing window has timed out."}]', 1, '2026-03-19 15:28:44.83466+05:30', '2026-03-19 15:28:44.83466+05:30');
INSERT INTO public.assistant_conversations VALUES (6, 3, 2, 'How to search old messages?', '[{"role": "user", "content": "How to search old messages?"}, {"role": "assistant", "content": "Okay, here’s how to search old messages in TheChatNest:\n\n1.  **Press Ctrl+F:** This is the quickest way to open the search bar. Alternatively, click the search icon located in the header of any chat window.\n\n2.  **Normal Search:** Type your keyword directly into the search bar. This will search across the entire database for messages containing that word.\n\n3.  **Smart Search:** To refine your search, toggle the “Smart” switch (it looks like a lightbulb) to the ‘on’ position. This allows you to use natural language. For example, you could type “files shared by Bhavesh last week” to find all files Bhavesh shared within the last seven days.\n\n4.  **Filter by Type:**  You can narrow your search by selecting the type of content you’re looking for.  Click the buttons for “Text,” “Image,” “Video,” “File,” “Link,” “Audio,” or “Code” to filter the results accordingly.\n\n5.  **Filter by User/Date Range:** You can also filter by user or date range.  To filter by user, click the user icon next to the search bar. To filter by date range, click the calendar icon next to the search bar and select the desired start and end dates."}]', 1, '2026-03-20 12:58:56.997361+05:30', '2026-03-20 12:58:56.997361+05:30');
INSERT INTO public.assistant_conversations VALUES (7, 2, 2, 'How to edit a message?', '[{"role": "user", "content": "How to edit a message?"}, {"role": "assistant", "content": "Okay, here’s how to edit a message in TheChatNest:\n\n1.  **Locate the Message:** Find the message you want to edit within the chat.\n2.  **Right-Click:** Right-click on the message.\n3.  **Select \"Edit\":** From the context menu that appears, click on the \"Edit\" option.\n4.  **Make Your Changes:** The message text box will open, allowing you to modify the text.\n5.  **Save Changes:** Once you’ve made your edits, click the \"Save\" button (it might appear automatically or you might need to click an \"Apply\" button).\n\n**Important Note:** There might be a time limit on how long you can edit a message. If you’ve exceeded the limit, you’ll receive a notification."}]', 1, '2026-03-20 15:53:30.896409+05:30', '2026-03-20 15:53:30.896409+05:30');
INSERT INTO public.assistant_conversations VALUES (8, 3, 2, 'How to edit a message?', '[{"role": "user", "content": "How to edit a message?"}, {"role": "assistant", "content": "# Editing a Sent Message ✏️\n\nHere''s how you can edit a message you''ve already sent:\n\n---\n\n### Steps to Edit a Message:\n\n1. **Locate** the message you want to edit in the chat\n2. **Right-click** on the message (or hover over it to reveal options)\n3. Click on **\"Edit\"** from the context menu\n4. The message will appear in the **input box** — make your changes\n5. Press **Enter** to save the edited message\n\n---\n\n### Things to Know:\n- ⏱️ **Time limit may apply** — you can only edit within a certain time window after sending\n- ✅ Edited messages will show an **\"Edited\"** label so others know it was modified\n- ❌ You can only edit **your own messages**, not others''\n\n---\n\n> 💡 **Tip:** If the edit option is greyed out, the time limit to edit that message may have passed. In that case, you can **delete & resend** the message instead."}]', 1, '2026-03-25 21:46:05.228336+05:30', '2026-03-25 21:46:05.228336+05:30');
INSERT INTO public.assistant_conversations VALUES (9, 3, 2, 'What are keyboard shortcuts?', '[{"role": "user", "content": "What are keyboard shortcuts?"}, {"role": "assistant", "content": "# Keyboard Shortcuts in TheChatNest ⌨️\n\nHere are the handy keyboard shortcuts available:\n\n---\n\n## ✍️ Text Formatting\n| Shortcut | Action |\n|----------|--------|\n| **Ctrl + B** | Bold text |\n| **Ctrl + I** | Italic text |\n| **Ctrl + U** | Underline text |\n\n---\n\n## 🔍 Search\n| Shortcut | Action |\n|----------|--------|\n| **Ctrl + F** | Open search in current chat |\n\n---\n\n## 💡 Pro Tips\n- **Rich Text**: Select any text you''ve typed, then apply formatting shortcuts\n- **Search + Smart Toggle**: After pressing Ctrl+F, enable the **\"Smart\"** toggle to search using natural language (e.g., *\"images shared by John last week\"*)\n\n---\n\n## 🖱️ Mouse Shortcuts (Bonus)\n| Action | How |\n|--------|-----|\n| Reply to message | Hover → click **Reply icon** or swipe right |\n| Edit sent message | Right-click → **Edit** |\n| Delete/Unsend message | Right-click → **Delete** or **Unsend** |\n| Pin a message | Right-click → **Pin** |\n| React with emoji | Hover → **emoji icon** |\n| Forward message | Right-click → **Forward** |\n| Summarize / Translate | Right-click → choose option |\n\n---"}]', 1, '2026-03-26 00:47:06.705821+05:30', '2026-03-26 00:47:06.705821+05:30');
INSERT INTO public.assistant_conversations VALUES (10, 3, 2, 'How to edit a message?', '[{"role": "user", "content": "How to edit a message?"}, {"role": "assistant", "content": "# How to Edit a Sent Message ✏️\n\nFollow these simple steps:\n\n1. **Hover** over the message you want to edit\n2. **Right-click** on the message\n3. Select **\"Edit\"** from the context menu\n4. **Modify** your message text in the input box\n5. Press **Enter** or click **Send** to save the changes\n\n> ⚠️ **Note:** A time limit may apply for editing messages. If the edit option is greyed out or not visible, the editing window may have expired.\n\n---\n\n**Things to keep in mind:**\n- Edited messages may show an **\"Edited\"** label so others know it was modified\n- Only **your own messages** can be edited\n- Editing works for **text messages** only (not files or images)"}]', 1, '2026-04-05 13:24:33.57836+05:30', '2026-04-05 13:24:33.57836+05:30');
