INSERT INTO public.feature_items VALUES (3, 1, 'Forkout', 'Broadcast a single message or attachment to multiple users and groups in one action.', NULL, 3, 'active', '2026-02-25 11:34:55.472974+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (1, 1, 'One-On-One Messaging', 'Converse instantly with a teammate and keep discussions focused with quick, reliable delivery.', NULL, 1, 'active', '2026-02-25 11:34:55.472974+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (7, 2, 'Role Based Group Control', 'Control who can post, edit group details, and manage members with granular permissions.', NULL, 3, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (8, 2, 'Airtime Groups', 'Make announcement-only groups where admins post updates without chat noise from members.', NULL, 2, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (9, 2, 'Group Messaging', 'Collaborate in shared channels with context-rich discussions for team and project workflows.', NULL, 1, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (10, 3, 'Join Now', 'Allow members to jump into ongoing calls instantly without restarting sessions.', NULL, 3, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (11, 3, 'Group Calling', 'Host stable multi-user meetings for department syncs, standups, and cross-team reviews.', NULL, 2, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (12, 3, 'One-On-One Audio & Video Call', 'Run secure and crisp 1:1 calls for faster decision-making and live collaboration.', NULL, 1, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (13, 4, 'Jointly Code', 'Collaborate in a shared code workspace during meetings for real-time implementation.', NULL, 3, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (14, 4, 'Remote Desktop Control', 'Grant controlled assistance sessions to resolve issues or guide task completion.', NULL, 2, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (15, 4, 'Remote Screen Share', 'Present your screen to remote users during calls for walkthroughs and support.', NULL, 1, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (16, 5, 'Self Message', 'Use a personal chat thread to capture notes, reminders, and work references.', NULL, 3, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (17, 5, 'Attachment Preview', 'Preview documents, images, videos, and PDFs directly in chat without downloads.', NULL, 2, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (18, 5, 'Quick Response Panel', 'Store reusable responses, snippets, links, and templates to reply faster.', NULL, 1, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (19, 6, 'Pinned Message Finder', 'Quickly access pinned items to keep important updates visible to the team.', NULL, 3, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (20, 6, 'Chat Area Filters', 'Narrow results inside active chat by files, links, media, and messages.', NULL, 2, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (21, 6, 'Global Search Filters', 'Filter by user, date range, media type, and keyword to find conversations faster.', NULL, 1, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
