INSERT INTO public.feature_items VALUES (31, 1, 'One-on-One Messaging', 'Send and receive direct messages in real-time with delivery and read receipts.', NULL, 1, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
