INSERT INTO public.feature_items VALUES (70, 5, 'Typing Indicator', 'See when other users are typing with real-time animated indicator.', NULL, 3, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (71, 5, 'Online Status', 'View user online, offline, or idle status with device type indicator.', NULL, 4, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (72, 5, 'Read Receipts', 'Single tick (sent), double tick (delivered), green tick (read) on messages.', NULL, 5, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (73, 5, 'Unread Count Badge', 'Real-time unread message count badge on chat sidebar threads.', NULL, 6, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (74, 5, 'User Timezone', 'Display all chat timestamps in user-selected timezone (335 timezones supported).', NULL, 7, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (75, 6, 'Filter by Images', 'Browse all shared images in a thread from the full database with counts.', NULL, 1, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (76, 6, 'Filter by Media', 'Browse all shared video and audio files in a thread.', NULL, 2, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (77, 6, 'Filter by Links', 'Browse all shared links with preview cards and hostname display.', NULL, 3, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (78, 6, 'Filter by Documents', 'Browse all shared documents, code files, and archives.', NULL, 4, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (79, 6, 'Filter by Pinned', 'View all messages you have pinned in a thread.', NULL, 5, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (24, 7, 'End-to-End Encryption', 'AES-256-GCM encryption for all messages and metadata across all channels.', NULL, 1, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (23, 7, 'Burnout Chat', 'Exchange sensitive details in self-destruct chat sessions without permanent history.', NULL, 2, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (82, 7, 'Dangerous File Blocking', 'Block executable and harmful file uploads (.exe, .bat, .dll, macros, etc.).', NULL, 3, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (83, 7, 'Trusted Device Management', 'View, manage, and revoke trusted devices from your account.', NULL, 4, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (84, 7, 'Session Control', 'Single device logout or logout all devices with session revocation.', NULL, 5, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (85, 7, 'CSRF Protection', 'Cross-Site Request Forgery protection on all unsafe HTTP methods.', NULL, 6, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (86, 7, 'Refresh Token Reuse Detection', 'Detect reused refresh tokens and force security logout across all devices.', NULL, 7, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (25, 8, 'Activity Logs', 'Track security, admin, and billing actions with audit-ready event history.', NULL, 1, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (26, 8, 'Organization Message Permissions', 'Control message actions like edit, delete, forward, and recall at org level.', NULL, 2, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (27, 8, 'Quick Add Users', 'Onboard new members rapidly using minimal required fields from admin panel.', NULL, 3, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (90, 8, 'Owner Dashboard', 'System monitoring with socket stats, database stats, and server health.', NULL, 4, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (91, 8, 'AI Provider Management', 'Configure and switch AI providers (Gemini, OpenAI, Claude) from owner dashboard.', NULL, 5, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (92, 8, 'Role-Based Access Control', 'Owner, admin, member, and restricted role permissions across the platform.', NULL, 6, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (93, 8, 'Organization Restrictions', 'IP-based and platform-based access restrictions for enhanced security.', NULL, 7, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (94, 8, 'Department & Designation Management', 'CRUD operations for departments, designations, and locations within the org.', NULL, 8, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (95, 8, 'Billing & Subscription', 'Plan pricing, coupon discounts, Stripe checkout, payment history, and PDF invoices.', NULL, 9, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (28, 9, 'AI Smart Search', 'Natural language search powered by AI. Ask questions like "files shared by Bhavesh last week".', NULL, 1, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (29, 9, 'AI Summary', 'Summarize messages, PDFs, DOCX, images, and code files into key bullet points.', NULL, 2, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (30, 9, 'AI Message Assist', 'Generate concise, professional drafts and improve clarity before sending.', NULL, 3, 'active', '2026-03-10 17:12:01.819711+05:30', '2026-03-10 17:12:01.819711+05:30');
INSERT INTO public.feature_items VALUES (99, 9, 'AI Tone Adjuster', 'Rewrite messages in Formal, Friendly, Diplomatic, or Professional tone.', NULL, 4, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (100, 9, 'AI Smart Compose', 'Real-time autocomplete suggestions as you type (10+ characters triggers AI).', NULL, 5, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (101, 9, 'AI Grammar Correction', 'Automatic grammar and spelling correction with accept/dismiss options.', NULL, 6, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (102, 9, 'AI Voice-to-Text', 'Convert audio and voice messages to polished text using OpenAI Whisper or Gemini.', NULL, 7, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (103, 9, 'AI Smart Reply', 'AI-generated 3 professional reply suggestions matching sender language.', NULL, 8, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (104, 9, 'AI Auto-Translate', 'Translate messages to any of 14 languages before sending with one-click convert.', NULL, 9, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (105, 9, 'AI Call Notes', 'Auto-generate structured meeting notes with summary, key points, and action items.', NULL, 10, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (106, 9, 'AI Semantic Search', 'Search messages by meaning, not exact keywords. Finds relevant results using AI.', NULL, 11, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (107, 9, 'AI Live Assistant', 'Intelligent role-aware AI support agent with conversation history and feedback.', NULL, 12, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (108, 28, 'Slack Integration', 'Connect TheChatNest with Slack for cross-platform messaging.', NULL, 1, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (109, 28, 'Google Workspace', 'Integrate with Google Drive, Calendar, and Meet.', NULL, 2, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (110, 28, 'Microsoft 365', 'Connect with Teams, OneDrive, and Outlook.', NULL, 3, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (111, 28, 'Webhook Support', 'Send and receive webhooks for custom automation workflows.', NULL, 4, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (112, 29, 'Auto-Responder', 'Set automatic replies when you are away or out of office.', NULL, 1, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (113, 29, 'Scheduled Messages', 'Schedule messages to be sent at a specific date and time.', NULL, 2, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (114, 29, 'Workflow Triggers', 'Automate actions based on message keywords, mentions, or events.', NULL, 3, 'active', '2026-03-26 23:03:09.883416+05:30', '2026-03-26 23:03:09.883416+05:30');
INSERT INTO public.feature_items VALUES (115, 1, 'Chat Mute (Per-Chat)', 'Mute individual chats for 1 hour, 8 hours, 1 week, or forever. Notifications are silently suppressed while badges still update.', NULL, 20, 'active', '2026-03-26 23:59:17.250523+05:30', '2026-03-26 23:59:17.250523+05:30');
INSERT INTO public.feature_items VALUES (116, 1, 'Scheduled Messages', 'Write a message and schedule it to be sent automatically at a specified date and time.', NULL, 21, 'active', '2026-03-26 23:59:17.250523+05:30', '2026-03-26 23:59:17.250523+05:30');
INSERT INTO public.feature_items VALUES (117, 1, 'GIF Picker (Tenor)', 'Search and send GIFs from Tenor directly in the chat composer.', NULL, 22, 'active', '2026-03-26 23:59:17.250523+05:30', '2026-03-26 23:59:17.250523+05:30');
INSERT INTO public.feature_items VALUES (118, 5, 'Do Not Disturb (DND)', 'Silence all notifications with a manual toggle or scheduled quiet hours in profile settings.', NULL, 10, 'active', '2026-03-26 23:59:17.250523+05:30', '2026-03-26 23:59:17.250523+05:30');
INSERT INTO public.feature_items VALUES (119, 1, 'Voice-to-Text Compose', 'Press the mic button and speak — your speech is converted to text in the message composer using Web Speech API.', NULL, 23, 'active', '2026-03-26 23:59:17.250523+05:30', '2026-03-26 23:59:17.250523+05:30');
INSERT INTO public.feature_items VALUES (120, 1, 'Broadcast List', 'Send one message to multiple contacts simultaneously as individual DMs.', NULL, 24, 'active', '2026-03-26 23:59:17.250523+05:30', '2026-03-26 23:59:17.250523+05:30');
INSERT INTO public.feature_items VALUES (121, 5, 'Custom Notification Sound Per Chat', 'Assign a unique notification tone to each chat for instant recognition.', NULL, 11, 'active', '2026-03-26 23:59:17.250523+05:30', '2026-03-26 23:59:17.250523+05:30');
INSERT INTO public.feature_items VALUES (122, 7, 'Disappearing Messages', 'Set a timer (24 hours, 7 days, or 30 days) after which messages automatically disappear from the chat.', NULL, 10, 'active', '2026-03-26 23:59:17.250523+05:30', '2026-03-26 23:59:17.250523+05:30');
